using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResource
{
    private static readonly Dictionary<string, object> AppConfig = new()
    {
        ["environment"] = "production",
        ["maxRetries"] = 3,
        ["timeout"] = 30,
        ["features"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["betaAccess"] = false
        }
    };

    [McpServerResource(UriTemplate = "config://app/settings", Name = "App Settings",
        MimeType = "application/json"), Description("Returns current application configuration")]
    public static string GetAppSettings() =>
        JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(UriTemplate = "config://app/features", Name = "Feature Flags",
        MimeType = "application/json"), Description("Returns feature flag status")]
    public static string GetFeatureFlags() =>
        JsonSerializer.Serialize(AppConfig["features"], new JsonSerializerOptions { WriteIndented = true });
}

using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Check if a specific feature flag is enabled")]
    public static string CheckFeature(
        [Description("Name of the feature flag to check")] string featureName)
    {
        var features = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["betaAccess"] = false
        };

        return features.TryGetValue(featureName, out var enabled)
            ? $"Feature '{featureName}' is {(enabled ? "enabled" : "disabled")}."
            : $"Feature '{featureName}' not found.";
    }

    [McpServerTool, Description("Get the current server environment name")]
    public static string GetEnvironment() => "production";
}

